mapper.insert:
/** CmmtMemberHistDao.insert */
insert into cmmt_member_hist (
	hist_id
	,hist_dt
	,work_type_nm
	,member_id
	,worker_id
	,work_cn
) values (
	#{histId}
	,#{histDt}
	,#{workTypeNm}
	,#{memberId}
	,#{workerId}
	,#{workCn}
)

/** CmmtMemberHistDao.insert */
insert into cmmt_member_hist (
	hist_id
	,hist_dt
	,work_type_nm
	,member_id
	,worker_id
	,work_cn
) values

(
	 #{item.histId}
	,#{item.histDt}
	,#{item.workTypeNm}
	,#{item.memberId}
	,#{item.workerId}
	,#{item.workCn}
)

mapper.select:
/** CmmtMemberHistDao.selectList */
select

	,row_number() over (order by hist_dt) as rn
from
	cmmt_member_hist
where
	member_id = #{memberId}
offset #{beginRowNum} -1
limit #{itemsPerPage}
